/**
 * Types for the [AreaMeasurementAnalysisView2D](https://developers.arcgis.com/javascript/latest/references/core/views/2d/analysis/AreaMeasurementAnalysisView2D/) and
 * [AreaMeasurementAnalysisView3D](https://developers.arcgis.com/javascript/latest/references/core/views/3d/analysis/AreaMeasurementAnalysisView3D/).
 *
 * @since 5.0
 */
import type { Area, Length } from "../../../core/quantity.js";
import type { MeasurementMode } from "../types.js";

/**
 * Result obtained from an [AreaMeasurementAnalysis](https://developers.arcgis.com/javascript/latest/references/core/analysis/AreaMeasurementAnalysis/).
 *
 * @since 5.0
 */
export interface AreaMeasurementResult {
  /**
   * Area of the polygon.
   *
   * @since 5.0
   */
  area: Area | null;
  /**
   * Specifies how the measurement is calculated.
   * Where `"euclidean"` denotes that polygon area and perimeter are computed on a flat (or "planar") surface.
   * Conversely, `"geodesic"` denotes that computations are performed on an ellipsoid.
   *
   * > [!WARNING]
   * >
   * > **Note**
   * >
   * > How the area and perimeter are computed depends on the view type, the spatial reference, and the measured perimeter.
   * >
   * > - In a [MapView](https://developers.arcgis.com/javascript/latest/references/core/views/MapView/) (2D):
   * >   - For **geographic coordinate systems** (GCS) and **Web Mercator**, measurements are calculated geodetically
   * >     (on the ellipsoid).
   * >   - For **projected coordinate systems** (PCS), apart from Web Mercator, the area and perimeter are always calculated
   * >     in a Euclidean (in their respective PCS).
   * >
   * >  - In a [SceneView](https://developers.arcgis.com/javascript/latest/references/core/views/SceneView/) (3D):
   * >   - For **geographic coordinate systems** (GCS) and **Web Mercator**, short measurements use a
   * >     Euclidean computation in an [ECEF](https://en.wikipedia.org/wiki/ECEF) (Earth-Centered, Earth-Fixed) coordinate
   * >     system (or an equivalent on other planets). Specifically, if the measurement's perimeter is ≤ 100 km the analysis
   * >     uses Euclidean calculations. If the perimeter is > 100 km, it uses geodetic calculations.
   * >   - For **projected coordinate systems** (PCS), apart from Web Mercator, the area and perimeter are always calculated
   * >     in a Euclidean (in their respective PCS).
   *
   * @since 5.0
   */
  mode: MeasurementMode;
  /**
   * Perimeter length of the polygon.
   *
   * @since 5.0
   */
  perimeter: Length | null;
}

/** @since 5.0 */
export interface AreaMeasurementPlacementResult {}